 32→					error instanceof Error &&
 33→					error.message.includes("INSERT race condition");
 34→				if (!isRaceCondition || attempt === 4) throw error;
 35→				await new Promise((r) => setTimeout(r, 1000 * 2 ** attempt));
 36→			}
 37→		}
