153→/**
154→ * Create a test user via better-auth sign-up and return a bearer token.
155→ */
156→export async function signUpTestUser(baseUrl: string): Promise<string> {
157→	const res = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
158→		method: "POST",
159→		headers: { "Content-Type": "application/json" },
160→		body: JSON.stringify({
161→			email: `test-${Date.now()}@example.com`,
162→			password: "test-password-123",
163→			name: "Test User",
164→		}),
165→	});
166→
167→	if (!res.ok) {
168→		const body = await res.text();
169→		throw new Error(`Sign-up failed (${res.status}): ${body}`);
170→	}
171→
172→	const data = (await res.json()) as { token?: string };
173→
174→	if (data.token) return data.token;
175→
176→	// Fallback: extract session token from set-cookie header
177→	const cookies = res.headers.getSetCookie();
178→	const sessionCookie = cookies
179→		.find((c) => c.startsWith("better-auth.session_token="))
180→		?.split("=")[1]
181→		?.split(";")[0];
182→
183→	if (sessionCookie) return sessionCookie;
184→
185→	throw new Error("Could not extract token from sign-up response");
186→}
